changeSet.sql:
ALTER TABLE wallet_ledger_entries DROP CONSTRAINT IF EXISTS wallet_ledger_entries_type_check;
ALTER TABLE wallet_ledger_entries ADD CONSTRAINT wallet_ledger_entries_type_check
    CHECK (type IN ('DEPOSIT', 'WITHDRAWAL', 'WITHDRAWAL_REVERSAL',
                    'TOURNAMENT_BUYIN', 'TOURNAMENT_PAYOUT', 'TOURNAMENT_REFUND'));
